<template><div class="panel"><div class="section-head"><div><h2>在线用户</h2><p>查看 Redis 会话并执行强制下线。</p></div><el-button @click="load">刷新</el-button></div><el-table :data="rows"><el-table-column prop="username" label="用户"/><el-table-column prop="ipAddress" label="IP"/><el-table-column prop="userAgent" label="客户端" show-overflow-tooltip/><el-table-column prop="loginAt" label="登录时间"/><el-table-column prop="lastActiveAt" label="最后活跃"/><el-table-column label="操作"><template #default="s"><el-button v-if="auth.hasPermission('system:session:terminate')" link type="danger" @click="terminate(s.row)">强制下线</el-button></template></el-table-column></el-table></div></template>
<script setup>import{onMounted,ref}from'vue';import{ElMessageBox}from'element-plus';import http from'../api/http';import{useAuthStore}from'../stores/auth';const auth=useAuthStore(),rows=ref([]);async function load(){rows.value=(await http.get('/system/online-sessions')).data}/** 强制撤销指定会话。 */async function terminate(row){await ElMessageBox.confirm(`确认下线用户「${row.username}」当前会话？`);await http.delete(`/system/online-sessions/${row.tokenId}`);await load()}onMounted(load)</script>
